sys_script_include.script:
var IDPGitHubConnector = Class.create();
IDPGitHubConnector.prototype = {
    initialize: function() {
        this.baseUrl = gs.getProperty('x_12345.idp.github.api_url');
        this.token = gs.getProperty('x_12345.idp.github.api_token');
    },

    fetchData: function(entityId) {
        try {
            var url = this.baseUrl + '/repos/' + entityId;

            var request = new sn_ws.RESTMessageV2();
            request.setEndpoint(url);
            request.setHttpMethod('GET');
            request.setRequestHeader('Authorization', 'token ' + this.token);
            request.setRequestHeader('Accept', 'application/vnd.github.v3+json');

            var response = request.execute();
            var responseBody = response.getBody();

            if (response.getStatusCode() == 200) {
                return JSON.parse(responseBody);
            }

            return null;
        } catch (ex) {
            gs.error('IDPGitHubConnector.fetchData failed: ' + ex.getMessage());
            return null;
        }
    },

    getRepositoryCommits: function(repo, branch) {
        try {
            var url = this.baseUrl + '/repos/' + repo + '/commits?sha=' + branch;

            var request = new sn_ws.RESTMessageV2();
            request.setEndpoint(url);
            request.setHttpMethod('GET');
            request.setRequestHeader('Authorization', 'token ' + this.token);
            request.setRequestHeader('Accept', 'application/vnd.github.v3+json');

            var response = request.execute();
            var responseBody = response.getBody();

            if (response.getStatusCode() == 200) {
                return JSON.parse(responseBody);
            }

            return [];
        } catch (ex) {
            gs.error('IDPGitHubConnector.getRepositoryCommits failed: ' + ex.getMessage());
            return [];
        }
    },

    type: 'IDPGitHubConnector'
};
